good-example.code-block:
package com.example.orders.service;

import com.example.orders.domain.OrderDocument;
import io.micronaut.data.exceptions.DataAccessException;
import com.mongodb.DuplicateKeyException;
import jakarta.inject.Singleton;

@Singleton
class OrderService {
    private final OrderRepository repository;

    OrderService(OrderRepository repository) {
        this.repository = repository;
    }

    OrderDocument save(OrderDocument doc) {
        try {
            return repository.save(doc);
        } catch (DuplicateKeyException ex) {
            throw new IllegalStateException("Duplicate order number", ex);
        } catch (DataAccessException ex) {
            throw new IllegalStateException("Mongo data access failure", ex);
        }
    }
}

bad-example.code-block:
package com.example.orders.service;

import com.example.orders.domain.OrderDocument;
import jakarta.inject.Singleton;

@Singleton
class BadOrderService {
    private final OrderRepository repository;

    BadOrderService(OrderRepository repository) {
        this.repository = repository;
    }

    OrderDocument save(OrderDocument doc) {
        try {
            return repository.save(doc);
        } catch (Exception e) {
            return null; // Bad: hides failure and corrupts control flow
        }
    }
}

